2056→+
2057→+/**
2058→+ * Subscribe to a native IPC event. Returns unsubscribe function.
2059→+ * In web mode, returns a no-op unsubscribe.
2060→+ *
2061→+ * Note: The returned cleanup function is synchronous, but the actual
2062→+ * listener registration is async (listen returns Promise<UnlistenFn>).
2063→+ * For React effects, call the returned fn in the cleanup. If the
2064→+ * listener hasn't resolved yet, it will be cleaned up when it does.
2065→+ */
2066→+export function on<K extends AppEventName>(
2067→+  event: K,
2068→+  callback: (data: AppEventMap[K]) => void
2069→+): () => void {
2070→+  if (!capabilities.ipcEventListeners) return () => {};
2071→+
2072→+  let cleanup: (() => void) | null = null;
2073→+  let cancelled = false;
2074→+
2075→+  // listen() returns Promise<UnlistenFn>
2076→+  listen(event, (e) => callback(e.payload as AppEventMap[K]))
2077→+    .then((unlisten) => {
2078→+      if (cancelled) {
2079→+        unlisten();
2080→+      } else {
2081→+        cleanup = unlisten;
2082→+      }
2083→+    })
2084→+    .catch(() => {});
2085→+
2086→+  return () => {
2087→+    cancelled = true;
2088→+    cleanup?.();
2089→+  };
2090→+}
2091→+
2092→+/**
2093→+ * Emit an event to the Electron main process (for cross-window relay).
2094→+ * No-op in web mode.
2095→+ */
2096→+export async function send<K extends AppEventName>(
2097→+  event: K,
2098→+  payload: AppEventMap[K]
2099→+): Promise<void> {
2100→+  if (!capabilities.ipcEventListeners) return;
2101→+  await emit(event, payload);
2102→+}
