735→        await native.browserViews.evaluate(label, "history.back();");
736→        // Wait for page load OR SPA url-change (SPAs don't trigger real page loads)
737→        const loadedUrl = await waitForPageLoad(label, 15_000, 500, true);
738→        console.log(
739→          `[BrowserRPC] NavigateBack → page loaded in ${Date.now() - t0}ms: ${loadedUrl}`
740→        );
741→        // Take a snapshot of the new page
742→        try {
743→          const resultStr = await evalWithResult(label, SNAPSHOT_JS, 12_000);
744→          const result = safeParseWebviewJson(resultStr);
745→          respond({ success: true, ...result });
746→        } catch (snapErr: unknown) {
747→          const snapMsg = getErrorMessage(snapErr);
748→          console.warn(`[BrowserRPC] Post-navigateBack snapshot failed: ${snapMsg}`);
749→          respond({
750→            success: true,
751→            snapshot: `Navigated back but snapshot failed: ${snapMsg}. Use BrowserSnapshot to retry.`,
752→          });
753→        }
754→      } catch (err: unknown) {
755→        const msg = getErrorMessage(err);
756→        console.error(`[BrowserRPC] NavigateBack failed:`, msg);
757→        respond({ success: false, error: msg });
758→      }
759→    },
760→    [resolveWebviewLabel]
761→  );
