763→  const handleBrowserConsoleMessages = useCallback(
764→    async (params: Record<string, unknown>, respond: RespondFn) => {
765→      const label = resolveWebviewLabel(
766→        params.webviewLabel as string | undefined,
767→        params.sessionId as string | undefined
768→      );
769→      if (!label) {
770→        respond({ logs: "", count: 0, error: "No active browser tab" });
771→        return;
772→      }
773→
774→      try {
775→        const resultStr = await evalWithResult(label, CONSOLE_MESSAGES_JS);
776→        const result = safeParseWebviewJson(resultStr);
