785→  const handleBrowserScreenshot = useCallback(
786→    async (params: Record<string, unknown>, respond: RespondFn) => {
787→      const label = resolveWebviewLabel(
788→        params.webviewLabel as string | undefined,
789→        params.sessionId as string | undefined
790→      );
791→      if (!label) {
792→        respond({ image: "", error: "No active browser tab" });
793→        return;
794→      }
795→
796→      try {
797→        // Build optional crop rect for screenshot command
798→        const rect = params.rect as
799→          | { x: number; y: number; width: number; height: number }
800→          | undefined;
801→        const screenshotOpts: Record<string, unknown> = {};
802→        if (rect) {
803→          screenshotOpts.rectX = rect.x;
804→          screenshotOpts.rectY = rect.y;
805→          screenshotOpts.rectWidth = rect.width;
806→          screenshotOpts.rectHeight = rect.height;
807→        }
808→
809→        // Call the native screenshot command (Electron BrowserView.capturePage)
810→        const base64 = await native.browserViews.screenshot(label, screenshotOpts);
811→
812→        // Visual feedback: camera flash effect AFTER capture (so it doesn't appear in the image)
813→        native.browserViews
