  1→/**
  2→ * API Configuration
  3→ * Central configuration for API endpoints and settings
  4→ *
  5→ * Port resolution:
  6→ * - Electron app: Uses preload bridge via window.electronAPI.getBackendPort()
  7→ * - Web dev: Uses VITE_BACKEND_PORT environment variable from dev.sh
  8→ */
  9→
 10→// Import directly from the source module (not the barrel) to avoid circular
 11→// dependency: client.ts → api.config.ts → platform/electron/index.ts → ... → client.ts
 12→import { isElectronEnv } from "@/platform/electron/invoke";
 13→
 14→let cachedPort: number | null = null;
 15→let portPromise: Promise<number> | null = null;
 16→
 17→// IPC retry config for backend port resolution.
 18→// The backend may not have emitted its [BACKEND_PORT] marker yet during early
 19→// startup — the main process waits for it before returning the port.
 20→// 30 attempts × 200ms = 6s covers the startup timeout with margin.
 21→const PORT_MAX_RETRIES = 30;
 22→const PORT_RETRY_DELAY_MS = 200;
 23→
 24→/**
 25→ * Get the backend port (cached after first call).
 26→ *
 27→ * In Electron mode, retries the IPC call with backoff because the backend may
 28→ * still be starting when the renderer first loads. Without retries, a single
 29→ * failed invoke permanently caches port 3333, causing all API requests to
 30→ * hit the wrong port and leaving the window hidden.
 31→ */
 32→export async function getBackendPort(): Promise<number> {
 33→  if (cachedPort !== null) {
 34→    return cachedPort;
 35→  }
 36→
 37→  // If there's already a pending request, return it
 38→  if (portPromise !== null) {
 39→    return portPromise;
 40→  }
 41→
 42→  portPromise = (async () => {
 43→    // 1. Check if running in web dev mode with dynamic port
 44→    if (import.meta.env.VITE_BACKEND_PORT) {
 45→      const port = parseInt(import.meta.env.VITE_BACKEND_PORT as string, 10);
 46→      if (!isNaN(port)) {
 47→        if (import.meta.env.DEV) console.log(`[API] Using web dev backend port: ${port}`);
 48→        cachedPort = port;
 49→        return port;
 50→      }
 51→    }
 52→
 53→    // 2. Electron: use the dedicated preload API (bypasses generic invoke bridge).
 54→    // The backend is spawned by the main process before the window is created,
 55→    // so the port should be available immediately via native:getBackendPort.
 56→    // Retry with backoff for the rare case where the renderer loads before the
 57→    // backend has emitted its [BACKEND_PORT] marker.
 58→    if (isElectronEnv) {
 59→      for (let attempt = 0; attempt < PORT_MAX_RETRIES; attempt++) {
 60→        try {
 61→          const port = await window.electronAPI!.getBackendPort();
 62→          if (import.meta.env.DEV)
 63→            console.log(`[API] Using Electron backend port: ${port} (attempt ${attempt + 1})`);
 64→          cachedPort = port;
 65→          return port;
 66→        } catch {
 67→          if (attempt < PORT_MAX_RETRIES - 1) {
 68→            await new Promise((resolve) => setTimeout(resolve, PORT_RETRY_DELAY_MS));
 69→          }
 70→        }
 71→      }
 72→      // All retries exhausted — don't cache a wrong port. Throw so TanStack Query
 73→      // retries the entire fetch later, giving the backend more time to start.
 74→      console.error("[API] getBackendPort failed after retries — backend may not have started");
 75→      throw new Error("Backend port not available after retries");
 76→    }
 77→
 78→    // 3. Dev mode: fetch port from Vite middleware (Electron writes it to temp file).
 79→    // This enables Chrome tabs at localhost:1420 to work during `bun run dev`.
 80→    if (import.meta.env.DEV) {
 81→      try {
 82→        const res = await fetch("/__backend_port");
 83→        if (res.ok) {
 84→          const data = await res.json();
 85→          if (data.port && typeof data.port === "number") {
 86→            console.log(`[API] Using backend port from dev server: ${data.port}`);
 87→            cachedPort = data.port;
 88→            return data.port;
 89→          }
 90→        }
 91→      } catch {
 92→        // Vite middleware not available
 93→      }
 94→    }
 95→
 96→    // 4. Last resort fallback — do NOT cache so retries re-resolve
 97→    // (e.g. user clicks Retry after backend finishes starting)
 98→    console.warn("[API] No port source available, falling back to default port 3333");
 99→    return 3333;
100→  })();
101→
102→  // Clear promise when done (success or failure)
103→  portPromise.finally(() => {
104→    portPromise = null;
105→  });
106→
107→  return portPromise;
108→}
109→
110→/**
111→ * Set the backend port directly and clear any in-flight resolution.
112→ * Called when the main process notifies the renderer of a backend restart
113→ * with a new port — the WebSocket reconnect loop will pick up the new port
114→ * on its next `getBackendPort()` call (which returns immediately from cache).
115→ */
116→export function setBackendPort(port: number): void {
117→  cachedPort = port;
118→  portPromise = null;
119→  if (import.meta.env.DEV) {
120→    console.log(`[API] Backend port updated to ${port} (backend restarted)`);
121→  }
122→}
123→
124→/**
125→ * Get the backend origin URL (e.g. http://localhost:12345)
126→ */
127→export async function getBackendUrl(): Promise<string> {
128→  const port = await getBackendPort();
129→  return `http://localhost:${port}`;
130→}
131→
132→/**
133→ * Get the base URL for API requests (async)
134→ */
135→export async function getBaseURL(): Promise<string> {
136→  const port = await getBackendPort();
137→  return `http://localhost:${port}/api`;
138→}
