 72→  useAnalyticsConsent();
 73→
 74→  // Auto-update: check on launch + every 5 min, show toast when ready
 75→  const autoUpdate = useAutoUpdate();
 76→  useUpdateToast(autoUpdate);
 77→
 78→  const showOnboarding = !settingsQuery.isError && !settingsQuery.data?.onboarding_completed;
 79→
 80→  // Boot diagnostics — trace the window-show flow so we can see what's blocking
 81→  useEffect(() => {
 82→    if (import.meta.env.DEV) {
 83→      console.log("[App] AppContent mount — auth:", {
 84→        isLoading: auth.isLoading,
 85→        isAuthenticated: auth.isAuthenticated,
 86→      });
 87→      console.log("[App] AppContent mount — settings:", {
 88→        isLoading: settingsQuery.isLoading,
 89→        isError: settingsQuery.isError,
 90→        hasData: !!settingsQuery.data,
 91→        onboardingCompleted: settingsQuery.data?.onboarding_completed,
 92→        showOnboarding,
 93→      });
 94→    }
 95→  }, [
 96→    auth.isLoading,
 97→    auth.isAuthenticated,
 98→    settingsQuery.isLoading,
 99→    settingsQuery.isError,
100→    settingsQuery.data,
101→    showOnboarding,
102→  ]);
103→
104→  // Show the main window whenever we transition OUT of onboarding.
105→  // Covers both first launch (window starts hidden, show: false in createWindow)
106→  // and replay-onboarding (exit_onboarding_mode hides the window).
107→  useEffect(() => {
108→    if (settingsQuery.isLoading) return;
109→    if (showOnboarding) {
110→      // Entering onboarding — reset so we re-show when it completes
111→      windowShownRef.current = false;
112→      return;
113→    }
114→    if (windowShownRef.current) return;
115→    native.window.show().catch(console.error);
116→    windowShownRef.current = true;
117→  }, [settingsQuery.isLoading, showOnboarding]);
118→
119→  // Remote browser auth gate: show pairing page if not authenticated
120→  if (auth.isLoading) return null;
121→  if (!auth.isAuthenticated) return <PairGatePage onPaired={auth.onPaired} />;
122→
123→  // While settings load, render nothing — window is hidden anyway
124→  if (settingsQuery.isLoading) return null;
125→
126→  // Backend unreachable — show error instead of white screen
127→  if (settingsQuery.isError && !settingsQuery.data) {
128→    return (
129→      <div className="bg-background flex h-screen items-center justify-center">
130→        <div className="max-w-md space-y-4 text-center">
131→          <h1 className="text-foreground text-xl font-semibold">Cannot connect to backend</h1>
132→          <p className="text-muted-foreground text-sm">
133→            {capabilities.windowLifecycle
134→              ? "The backend server failed to start. Check the terminal for errors."
135→              : "Run `bun run dev:web` for browser development, or use the Electron desktop app (`bun run dev`)."}
136→          </p>
137→          <button
138→            type="button"
139→            onClick={() => settingsQuery.refetch()}
140→            className="bg-primary text-primary-foreground hover:bg-primary/90 rounded-lg px-4 py-2 text-sm font-medium"
141→          >
142→            Retry
143→          </button>
144→        </div>
145→      </div>
146→    );
147→  }
148→
149→  if (showOnboarding) {
150→    return <OnboardingOverlay />;
151→  }
152→
153→  return (
154→    <UpdateProvider value={autoUpdate}>
155→      <BrowserRouter>
156→        <Routes>
157→          <Route
158→            path="/"
159→            element={
160→              <ErrorBoundary
161→                FallbackComponent={DashboardError}
162→                onReset={reset}
163→                onError={createBoundaryErrorHandler("react.error-boundary.root")}
164→              >
165→                <MainLayout />
166→              </ErrorBoundary>
167→            }
168→          />
169→        </Routes>
170→      </BrowserRouter>
171→      <Toaster />
172→    </UpdateProvider>
173→  );
174→}
175→
176→/**
177→ * Safety net: ensure the window always becomes visible.
178→ *
179→ * The main window starts hidden (show: false in createWindow) to avoid
180→ * a flash before onboarding/content is ready. Normally the frontend calls
181→ * show_main_window or enter_onboarding_mode within ~1-2s. But if anything
182→ * goes wrong (settings fetch hangs, unexpected error, hook crash), the window
183→ * stays hidden and the user sees only a dock icon with no window.
184→ *
185→ * This timeout guarantees the window appears within WINDOW_SHOW_TIMEOUT_MS,
186→ * no matter what. It's a last resort — the normal flow or ErrorFallback
187→ * should show the window sooner.
188→ */
189→const WINDOW_SHOW_TIMEOUT_MS = 5_000;
190→
191→function useWindowShowSafetyNet() {
192→  const shownRef = useRef(false);
193→  useEffect(() => {
194→    if (shownRef.current || !capabilities.windowLifecycle) return;
195→    const timer = setTimeout(() => {
196→      if (!shownRef.current) {
197→        shownRef.current = true;
198→        console.warn("[App] Safety net: force-showing window after timeout");
199→        native.window.show().catch(console.error);
200→      }
201→    }, WINDOW_SHOW_TIMEOUT_MS);
202→    return () => clearTimeout(timer);
203→  }, []);
204→}
205→
206→function App() {
207→  // Safety net — force-show window if nothing else does within 5s
208→  useWindowShowSafetyNet();
209→
210→  const content = isDetachedBrowser ? (
211→    // Detached browser window: minimal shell with just the browser panel
212→    <QueryClientProvider>
213→      <ThemeProvider>
214→        <DetachedBrowserWindow />
215→      </ThemeProvider>
216→    </QueryClientProvider>
217→  ) : (
218→    <QueryClientProvider>
219→      <QueryErrorResetBoundary>
220→        {({ reset }) => (
221→          <ErrorBoundary
222→            FallbackComponent={ErrorFallback}
223→            onReset={reset}
224→            onError={createBoundaryErrorHandler("react.error-boundary")}
225→          >
226→            <ThemeProvider>
227→              <AppContent reset={reset} />
228→            </ThemeProvider>
229→          </ErrorBoundary>
230→        )}
231→      </QueryErrorResetBoundary>
232→    </QueryClientProvider>
233→  );
234→
235→  return (
236→    <LazyMotion features={domAnimation} strict>
237→      {content}
238→    </LazyMotion>
239→  );
240→}
241→
242→export default App;
