  1→// src/features/browser/automation/useBrowserRpcHandler.ts
  2→// Handles browser automation RPC requests from the agent-server.
  3→//
  4→// Architecture:
  5→//   Agent-server → Backend → q:event tool:request → this handler
  6→//   Handler executes JS in webview via evalWithResult → sends q:tool_response back via WS
  7→
  8→import { match } from "ts-pattern";
  9→import { useEffect, useCallback, useRef } from "react";
 10→import { native } from "@/platform";
 11→import { native } from "@/platform";
 12→import { BROWSER_PAGE_LOAD, BROWSER_URL_CHANGE } from "@shared/events";
 13→import { getErrorMessage } from "@shared/lib/errors";
 14→import { evalWithResult } from "./eval-with-result";
 15→import {
 16→  SNAPSHOT_JS,
 17→  CONSOLE_MESSAGES_JS,
 18→  NETWORK_REQUESTS_JS,
 19→  buildClickJs,
 20→  buildTypeJs,
 21→  buildWaitForTextJs,
 22→  buildWaitForTextGoneJs,
 23→  buildHoverJs,
 24→  buildPressKeyJs,
 25→  buildSelectOptionJs,
 26→  buildEvaluateJs,
 27→  buildScrollJs,
 28→} from "./browser-utils";
 29→import {
 30→  buildMoveCursorAndRippleJs,
 31→  buildPinCursorJs,
 32→  HIDE_CURSOR_JS,
 33→  buildFadeCursorJs,
 34→  buildScreenshotFlashJs,
 35→  SCAN_PAGE_JS,
 36→  KEY_FLASH_JS,
 37→} from "./visual-effects";
 38→import type { BrowserTabState } from "../types";
 39→import { useWsToolRequest } from "@/shared/hooks/useWsToolRequest";
 40→
 41→/**
 42→ * Safely parse JSON from webview evalWithResult responses.
 43→ * Webview responses are untrusted — malformed HTML error pages, partial
 44→ * output, or encoding issues can produce invalid JSON. This wrapper
 45→ * throws a descriptive error instead of the raw SyntaxError.
 46→ */
 47→function safeParseWebviewJson<T = Record<string, unknown>>(raw: string): T {
 48→  try {
 49→    return JSON.parse(raw) as T;
 50→  } catch {
 51→    const preview = raw.length > 200 ? raw.slice(0, 200) + "..." : raw;
 52→    throw new Error(`Malformed JSON from webview: ${preview}`);
 53→  }
 54→}
 55→
 56→/**
 57→ * Play a visual cursor effect (move+ripple or pin) and wait for its
 58→ * animation duration. Non-critical — silently swallows errors so the
 59→ * actual browser action always proceeds.
 60→ */
 61→async function playCursorEffect(label: string, effectJs: string): Promise<void> {
 62→  try {
 63→    const result = await evalWithResult(label, effectJs, 3000);
 64→    const parsed = safeParseWebviewJson<{ duration?: number }>(result);
 65→    if (parsed.duration && parsed.duration > 0)
 66→      await new Promise((r) => setTimeout(r, parsed.duration));
 67→  } catch {
 68→    /* visual effects are non-critical */
 69→  }
 70→}
 71→
 72→/**
 73→ * Waits for the `browser:page-load` IPC event with event="finished"
 74→ * for the given webview label. This is emitted by Electron's `did-finish-load`
 75→ * callback — no polling needed.
 76→ *
 77→ * When `alsoListenUrlChange` is true (for history.back() in SPAs), also
 78→ * resolves on `browser:url-change` since SPA routers don't trigger a
 79→ * real page load — they fire popstate which emits url-change instead.
 80→ *
 81→ * After the page finishes loading, waits a short DOM-settle delay so
 82→ * frameworks (React, Next.js, etc.) can hydrate before we snapshot.
 83→ */
 84→async function waitForPageLoad(
 85→  label: string,
 86→  timeoutMs = 15_000,
 87→  settleMs = 500,
 88→  alsoListenUrlChange = false
 89→): Promise<string> {
 90→  return new Promise<string>((resolve, reject) => {
 91→    let settled = false;
 92→    const unlistenFns: (() => void)[] = [];
 93→
 94→    function cleanup() {
 95→      for (const fn of unlistenFns) fn();
 96→    }
 97→
 98→    const timer = setTimeout(() => {
 99→      if (!settled) {
100→        settled = true;
101→        cleanup();
102→        reject(new Error(`Page did not finish loading within ${timeoutMs}ms`));
103→      }
104→    }, timeoutMs);
105→
106→    function onLoad(url: string) {
107→      if (!settled) {
108→        settled = true;
109→        clearTimeout(timer);
110→        cleanup();
111→        // Short settle for framework hydration (React, Next.js, etc.)
112→        setTimeout(() => resolve(url), settleMs);
113→      }
114→    }
115→
116→    // Primary: browser:page-load (real navigations)
117→    const unlistenPageLoad = native.events.on(BROWSER_PAGE_LOAD, (data) => {
118→      const payload = data as { label: string; event: string; url: string };
119→      if (payload.label === label && payload.event === "finished") {
120→        onLoad(payload.url);
121→      }
122→    });
123→    unlistenFns.push(unlistenPageLoad);
124→
125→    // Secondary: browser:url-change (SPA navigations via popstate)
126→    if (alsoListenUrlChange) {
127→      const unlistenUrlChange = native.events.on(BROWSER_URL_CHANGE, (data) => {
128→        const payload = data as { label: string; url: string };
129→        if (payload.label === label) {
130→          onLoad(payload.url);
131→        }
132→      });
133→      unlistenFns.push(unlistenUrlChange);
134→    }
135→  });
136→}
