138→// ---- Response helper type ----
139→
140→/** Response function for tool request handlers. */
141→type RespondFn = (result: unknown) => void;
142→
143→/**
144→ * Hook that handles browser automation RPC requests from the sidecar.
145→ *
146→ * Listens for WS tool requests (via `useWsToolRequest`), dispatches to the appropriate
147→ * handler based on method name, and sends JSON-RPC responses back to the sidecar.
148→ *
149→ * @param getActiveTab - Function to get the current active browser tab state
150→ * @param onAutoCreateTab - Optional callback to auto-create a browser tab when
151→ *   BrowserNavigate is called with no existing tab. Returns the new webviewLabel
152→ *   or null if creation failed. Navigate auto-creates a tab if none exists.
153→ * @param getTabs - Optional function to get all browser tabs for session-mapped lookups
154→ */
155→export function useBrowserRpcHandler(
156→  getActiveTab: () => BrowserTabState | null,
157→  onAutoCreateTab?: (url: string) => string | null,
158→  workspaceId?: string | null,
159→  getTabs?: () => BrowserTabState[]
160→) {
161→  const getActiveTabRef = useRef(getActiveTab);
162→  const getTabsRef = useRef(getTabs);
163→  const onAutoCreateTabRef = useRef(onAutoCreateTab);
164→
165→  useEffect(() => {
166→    getActiveTabRef.current = getActiveTab;
167→  }, [getActiveTab]);
168→
169→  useEffect(() => {
170→    getTabsRef.current = getTabs;
171→  }, [getTabs]);
172→
173→  useEffect(() => {
174→    onAutoCreateTabRef.current = onAutoCreateTab;
175→  }, [onAutoCreateTab]);
176→
177→  // Guard against rapid duplicate auto-create calls
178→  const autoCreatePendingRef = useRef<string | null>(null);
179→
180→  // Session → webviewLabel mapping for multi-agent tab isolation.
181→  // Each session (agent) navigates to its own tab; subsequent operations
182→  // (snapshot, click, type, waitFor) target that session's tab automatically.
183→  const sessionTabMapRef = useRef(new Map<string, string>());
184→
185→  // Clear session→tab map on workspace switch
186→  const prevWorkspaceIdRef = useRef(workspaceId);
187→  useEffect(() => {
188→    if (prevWorkspaceIdRef.current === workspaceId) return;
189→    sessionTabMapRef.current.clear();
190→    autoCreatePendingRef.current = null;
191→    prevWorkspaceIdRef.current = workspaceId;
192→  }, [workspaceId]);
193→
194→  const resolveWebviewLabel = useCallback(
195→    (requestedLabel?: string, sessionId?: string): string | null => {
196→      if (requestedLabel) return requestedLabel;
197→      // Check session→tab mapping first (multi-agent isolation)
198→      if (sessionId) {
199→        const mapped = sessionTabMapRef.current.get(sessionId);
200→        if (mapped) return mapped;
201→      }
202→      const tab = getActiveTabRef.current();
203→      return tab?.webviewLabel ?? null;
204→    },
205→    []
206→  );
207→
208→  const handleBrowserSnapshot = useCallback(
209→    async (params: Record<string, unknown>, respond: RespondFn) => {
210→      const label = resolveWebviewLabel(
211→        params.webviewLabel as string | undefined,
212→        params.sessionId as string | undefined
213→      );
214→      if (!label) {
215→        respond({ error: "No active browser tab" });
216→        return;
217→      }
218→
219→      try {
220→        // Visual feedback: scan-line to show the AI is reading the page (best-effort, fire-and-forget)
221→        native.browserViews.evaluate(label, SCAN_PAGE_JS).catch(() => {});
222→
223→        // Heavy pages (e.g. portals) can have 10k+ DOM nodes — the
224→        // accessibility tree builder needs more time than the default 8s.
225→        const t0 = Date.now();
226→        const resultStr = await evalWithResult(label, SNAPSHOT_JS, 15_000);
227→        const result = safeParseWebviewJson(resultStr);
228→        console.log(`[BrowserRPC] Snapshot completed in ${Date.now() - t0}ms`);
229→        respond(result);
230→      } catch (err: unknown) {
231→        // Clear stale session mapping so next BrowserNavigate triggers auto-create
232→        const msg = getErrorMessage(err);
233→        if (msg.includes("not found") && params.sessionId) {
234→          sessionTabMapRef.current.delete(params.sessionId as string);
235→        }
236→        console.error(`[BrowserRPC] Snapshot failed:`, msg);
237→        respond({
238→          error: msg.includes("not found")
239→            ? "Browser tab not found. Use BrowserNavigate to open a page first."
240→            : msg,
241→        });
242→      }
243→    },
244→    [resolveWebviewLabel]
245→  );
246→
247→  const handleBrowserClick = useCallback(
248→    async (params: Record<string, unknown>, respond: RespondFn) => {
249→      const label = resolveWebviewLabel(
250→        params.webviewLabel as string | undefined,
251→        params.sessionId as string | undefined
252→      );
253→      if (!label) {
254→        respond({ success: false, error: "No active browser tab" });
255→        return;
256→      }
257→
258→      const ref = params.ref as string;
259→      const doubleClick = params.doubleClick as boolean | undefined;
260→      if (!ref) {
261→        respond({ success: false, error: "Missing ref parameter" });
262→        return;
263→      }
264→
265→      try {
266→        await playCursorEffect(label, buildMoveCursorAndRippleJs(ref));
267→
268→        const js = buildClickJs(ref, doubleClick);
269→        const resultStr = await evalWithResult(label, js);
270→        const result = safeParseWebviewJson(resultStr);
271→
272→        // Fade cursor out gracefully after click (dwell 600ms then fade)
273→        native.browserViews.evaluate(label, buildFadeCursorJs()).catch(() => {});
274→
275→        respond(result);
276→      } catch (err: unknown) {
277→        respond({ success: false, error: getErrorMessage(err) });
278→      }
279→    },
280→    [resolveWebviewLabel]
281→  );
282→
283→  const handleBrowserType = useCallback(
284→    async (params: Record<string, unknown>, respond: RespondFn) => {
285→      const label = resolveWebviewLabel(
286→        params.webviewLabel as string | undefined,
287→        params.sessionId as string | undefined
288→      );
289→      if (!label) {
290→        respond({ success: false, error: "No active browser tab" });
291→        return;
292→      }
293→
294→      const ref = params.ref as string;
295→      const text = params.text as string;
296→      const submit = params.submit as boolean | undefined;
297→      const slowly = params.slowly as boolean | undefined;
298→      if (!ref || text === undefined) {
299→        respond({ success: false, error: "Missing ref or text parameter" });
300→        return;
301→      }
302→
303→      try {
304→        await playCursorEffect(label, buildPinCursorJs(ref));
305→
306→        const js = buildTypeJs(ref, text, submit, slowly);
307→        const resultStr = await evalWithResult(label, js);
308→        const result = safeParseWebviewJson(resultStr);
309→
310→        // Unpin cursor after typing completes (best-effort)
