318→    [resolveWebviewLabel]
319→  );
320→
321→  const handleBrowserNavigate = useCallback(
322→    async (params: Record<string, unknown>, respond: RespondFn) => {
323→      const sessionId = params.sessionId as string | undefined;
324→      let label = resolveWebviewLabel(params.webviewLabel as string | undefined, sessionId);
325→
326→      const url = params.url as string;
327→      if (!url) {
328→        respond({ success: false, error: "Missing url parameter" });
329→        return;
330→      }
331→
332→      // Check if the active tab actually has a native webview.
333→      // BrowserPanel always creates a default empty "New Tab" which has a
334→      // webviewLabel in React state but NO native WKWebView (no URL loaded).
335→      // In that case, we route through auto-create to populate the empty tab.
336→      if (label && !params.webviewLabel) {
337→        const tab = getActiveTabRef.current();
338→        if (tab && !tab.currentUrl) {
339→          label = null; // Empty tab → treat as no-tab for auto-create
340→        }
341→      }
342→
343→      // Auto-create (or populate empty tab) if no usable webview exists
344→      if (!label) {
