346→        if (!autoCreate) {
347→          respond({ success: false, error: "No active browser tab" });
348→          return;
349→        }
350→
351→        // Reuse pending auto-create if one is already in flight
352→        if (autoCreatePendingRef.current) {
353→          label = autoCreatePendingRef.current;
354→        } else {
355→          const newLabel = autoCreate(url);
356→          if (!newLabel) {
