367→        }
368→
369→        try {
370→          // Wait for React to render BrowserTab → create webview → page finish
371→          const t0 = Date.now();
372→          const loadedUrl = await waitForPageLoad(label);
373→          console.log(
374→            `[BrowserRPC] Navigate (auto-create) → page loaded in ${Date.now() - t0}ms: ${loadedUrl}`
375→          );
376→          autoCreatePendingRef.current = null;
377→
378→          // Take a snapshot of the loaded page (best-effort: heavy pages
379→          // may not be ready for DOM traversal immediately after loading).
380→          // If snapshot fails, still report success — the page loaded and
381→          // the agent can use BrowserSnapshot later.
382→          try {
383→            const resultStr = await evalWithResult(label, SNAPSHOT_JS, 12_000);
384→            const result = safeParseWebviewJson(resultStr);
385→            respond({ success: true, webviewLabel: label, ...result });
386→          } catch (snapErr: unknown) {
387→            const snapMsg = getErrorMessage(snapErr);
388→            console.warn(`[BrowserRPC] Post-navigate snapshot failed: ${snapMsg}`);
389→            respond({
390→              success: true,
391→              webviewLabel: label,
392→              snapshot: `Page loaded but snapshot failed: ${snapMsg}. Use BrowserSnapshot to retry.`,
393→            });
394→          }
395→        } catch (err: unknown) {
396→          autoCreatePendingRef.current = null;
397→          const msg = getErrorMessage(err);
398→          console.error(`[BrowserRPC] Auto-create navigation failed:`, msg);
399→          respond({
400→            success: false,
401→            error: msg,
402→          });
403→        }
404→        return;
405→      }
406→
407→      // Register session→tab mapping for multi-agent isolation
408→      if (sessionId) {
409→        sessionTabMapRef.current.set(sessionId, label);
410→      }
411→
412→      try {
413→        const t0 = Date.now();
414→        await native.browserViews.navigate(label, url);
415→        // Wait for page to finish loading (event-based, not polling)
416→        const loadedUrl = await waitForPageLoad(label);
417→        console.log(
418→          `[BrowserRPC] Navigate (existing tab) → page loaded in ${Date.now() - t0}ms: ${loadedUrl}`
419→        );
420→        // Take a snapshot (best-effort — heavy pages may timeout)
421→        try {
422→          const resultStr = await evalWithResult(label, SNAPSHOT_JS, 12_000);
423→          const result = safeParseWebviewJson(resultStr);
424→          respond({ success: true, webviewLabel: label, ...result });
425→        } catch (snapErr: unknown) {
426→          const snapMsg = getErrorMessage(snapErr);
427→          console.warn(`[BrowserRPC] Post-navigate snapshot failed: ${snapMsg}`);
428→          respond({
429→            success: true,
430→            webviewLabel: label,
431→            snapshot: `Page loaded but snapshot failed: ${snapMsg}. Use BrowserSnapshot to retry.`,
432→          });
433→        }
434→      } catch (err: unknown) {
435→        // If the webview no longer exists (stale mapping from previous session
436→        // or workspace switch), clear the mapping and retry via auto-create.
437→        const msg = getErrorMessage(err);
438→        const isStale = msg.includes("not found");
