448→            if (newLabel) {
449→              sessionTabMapRef.current.set(sessionId, newLabel);
450→              try {
451→                const loadedUrl = await waitForPageLoad(newLabel);
452→                console.log(`[BrowserRPC] Navigate (auto-create after stale) → ${loadedUrl}`);
453→                try {
454→                  const resultStr = await evalWithResult(newLabel, SNAPSHOT_JS, 12_000);
455→                  const result = safeParseWebviewJson(resultStr);
456→                  respond({ success: true, webviewLabel: newLabel, ...result });
457→                } catch {
458→                  respond({
459→                    success: true,
460→                    webviewLabel: newLabel,
461→                    snapshot: "Page loaded. Use BrowserSnapshot to inspect.",
462→                  });
463→                }
464→                return;
465→              } catch (retryErr: unknown) {
466→                console.error(
467→                  `[BrowserRPC] Auto-create retry also failed:`,
468→                  getErrorMessage(retryErr)
469→                );
470→              }
471→            }
472→          }
473→        }
