769→      if (!label) {
770→        respond({ logs: "", count: 0, error: "No active browser tab" });
771→        return;
772→      }
773→
774→      try {
775→        const resultStr = await evalWithResult(label, CONSOLE_MESSAGES_JS);
776→        const result = safeParseWebviewJson(resultStr);
777→        respond(result);
778→      } catch (err: unknown) {
779→        respond({ logs: "", count: 0, error: getErrorMessage(err) });
780→      }
781→    },
782→    [resolveWebviewLabel]
783→  );
784→
785→  const handleBrowserScreenshot = useCallback(
786→    async (params: Record<string, unknown>, respond: RespondFn) => {
787→      const label = resolveWebviewLabel(
788→        params.webviewLabel as string | undefined,
789→        params.sessionId as string | undefined
790→      );
791→      if (!label) {
792→        respond({ image: "", error: "No active browser tab" });
793→        return;
794→      }
795→
796→      try {
797→        // Build optional crop rect for screenshot command
798→        const rect = params.rect as
799→          | { x: number; y: number; width: number; height: number }
800→          | undefined;
801→        const screenshotOpts: Record<string, unknown> = {};
802→        if (rect) {
803→          screenshotOpts.rectX = rect.x;
804→          screenshotOpts.rectY = rect.y;
805→          screenshotOpts.rectWidth = rect.width;
806→          screenshotOpts.rectHeight = rect.height;
807→        }
808→
809→        // Call the native screenshot command (Electron BrowserView.capturePage)
810→        const base64 = await native.browserViews.screenshot(label, screenshotOpts);
811→
812→        // Visual feedback: camera flash effect AFTER capture (so it doesn't appear in the image)
813→        native.browserViews
814→          .evaluate(label, buildScreenshotFlashJs(rect ?? undefined))
815→          .catch(() => {});
816→        // Best-effort URL + title for context
817→        const url = await native.browserViews.getUrl(label);
818→        respond({ image: base64, url, title: "" });
819→      } catch (err: unknown) {
820→        // Clear stale session mapping so next BrowserNavigate triggers auto-create
821→        const msg = getErrorMessage(err);
822→        if (msg.includes("not found") && params.sessionId) {
823→          sessionTabMapRef.current.delete(params.sessionId as string);
824→        }
825→        respond({
826→          image: "",
827→          error: msg.includes("not found")
828→            ? "Browser tab not found. Use BrowserNavigate to open a page first."
829→            : msg,
830→        });
831→      }
832→    },
833→    [resolveWebviewLabel]
834→  );
835→
836→  const handleBrowserNetworkRequests = useCallback(
837→    async (params: Record<string, unknown>, respond: RespondFn) => {
838→      const label = resolveWebviewLabel(
839→        params.webviewLabel as string | undefined,
840→        params.sessionId as string | undefined
841→      );
842→      if (!label) {
843→        respond({ requests: "", count: 0, error: "No active browser tab" });
844→        return;
845→      }
846→
847→      try {
848→        const resultStr = await evalWithResult(label, NETWORK_REQUESTS_JS);
849→        const result = safeParseWebviewJson(resultStr);
850→        respond(result);
851→      } catch (err: unknown) {
852→        respond({ requests: "", count: 0, error: getErrorMessage(err) });
853→      }
854→    },
855→    [resolveWebviewLabel]
856→  );
857→
858→  const handleBrowserScroll = useCallback(
859→    async (params: Record<string, unknown>, respond: RespondFn) => {
860→      const label = resolveWebviewLabel(
861→        params.webviewLabel as string | undefined,
862→        params.sessionId as string | undefined
863→      );
864→      if (!label) {
865→        respond({ success: false, error: "No active browser tab" });
866→        return;
867→      }
868→
869→      const direction = params.direction as string | undefined;
870→      const amount = params.amount as number | undefined;
871→      const ref = params.ref as string | undefined;
872→
873→      try {
874→        const js = buildScrollJs(direction, amount, ref);
875→        const resultStr = await evalWithResult(label, js);
876→        const result = safeParseWebviewJson(resultStr);
877→        respond(result);
878→      } catch (err: unknown) {
879→        respond({ success: false, error: getErrorMessage(err) });
880→      }
881→    },
882→    [resolveWebviewLabel]
883→  );
884→
885→  // ============================================================================
886→  // Dispatch helper
887→  // ============================================================================
888→
889→  const dispatchBrowserMethod = useCallback(
890→    (
891→      method: string,
892→      params: Record<string, unknown>,
893→      respond: RespondFn,
894→      respondError?: (error: string) => void
895→    ) => {
896→      match(method)
897→        .with("browserSnapshot", () => handleBrowserSnapshot(params, respond))
898→        .with("browserClick", () => handleBrowserClick(params, respond))
899→        .with("browserType", () => handleBrowserType(params, respond))
900→        .with("browserNavigate", () => handleBrowserNavigate(params, respond))
901→        .with("browserGetState", () => handleBrowserGetState(params, respond))
902→        .with("browserWaitFor", () => handleBrowserWaitFor(params, respond))
903→        .with("browserEvaluate", () => handleBrowserEvaluate(params, respond))
904→        .with("browserPressKey", () => handleBrowserPressKey(params, respond))
905→        .with("browserHover", () => handleBrowserHover(params, respond))
906→        .with("browserSelectOption", () => handleBrowserSelectOption(params, respond))
907→        .with("browserNavigateBack", () => handleBrowserNavigateBack(params, respond))
908→        .with("browserConsoleMessages", () => handleBrowserConsoleMessages(params, respond))
909→        .with("browserNetworkRequests", () => handleBrowserNetworkRequests(params, respond))
910→        .with("browserScreenshot", () => handleBrowserScreenshot(params, respond))
911→        .with("browserScroll", () => handleBrowserScroll(params, respond))
912→        .otherwise(() => {
913→          if (method.startsWith("browser") && respondError) {
914→            respondError(`Unknown browser method: ${method}`);
915→          }
916→        });
917→    },
918→    [
919→      handleBrowserSnapshot,
920→      handleBrowserClick,
921→      handleBrowserType,
922→      handleBrowserNavigate,
923→      handleBrowserGetState,
924→      handleBrowserWaitFor,
925→      handleBrowserEvaluate,
926→      handleBrowserPressKey,
927→      handleBrowserHover,
928→      handleBrowserSelectOption,
929→      handleBrowserNavigateBack,
930→      handleBrowserConsoleMessages,
931→      handleBrowserNetworkRequests,
932→      handleBrowserScreenshot,
933→      handleBrowserScroll,
934→    ]
935→  );
936→
937→  // ============================================================================
938→  // WS event listener (agent-server → backend → q:event tool:request)
939→  // ============================================================================
940→
941→  useWsToolRequest((method, requestId, params, respond, respondError) => {
942→    if (import.meta.env.DEV) {
943→      console.log("[BrowserRPC] Received request (WS):", method, "requestId:", requestId);
944→    }
945→
946→    dispatchBrowserMethod(method, params, respond, respondError);
947→  });
948→}
