 1→/**
 2→ * Hook to manage detaching/reattaching the browser into a separate OS window.
 3→ *
 4→ * In Electron, uses window.electronAPI.invoke to create a new BrowserWindow
 5→ * that loads the same React app with a query param (?window=browser-detached).
 6→ * Detached window state is tracked globally (runtime only) because there is
 7→ * only one physical detached browser window across all workspaces.
 8→ */
 9→
10→import { useCallback, useEffect } from "react";
11→import { native } from "@/platform";
12→import { BROWSER_WORKSPACE_CHANGE } from "@shared/events";
13→import {
14→  browserWindowActions,
15→  useBrowserWindowStore,
16→  type DetachedBrowserWorkspaceContext,
17→} from "@/features/browser/store";
18→
19→function buildDetachUrl(context: DetachedBrowserWorkspaceContext): string {
20→  const params = new URLSearchParams({
21→    window: "browser-detached",
22→    workspaceId: context.workspaceId,
23→  });
24→  if (context.directoryName) params.set("directoryName", context.directoryName);
25→  if (context.repoName) params.set("repoName", context.repoName);
26→  if (context.branch) params.set("branch", context.branch);
27→  return `/?${params.toString()}`;
28→}
29→
30→function buildWindowTitle(context: DetachedBrowserWorkspaceContext): string {
31→  const repo = context.repoName ?? context.directoryName ?? "Workspace";
32→  const branch = context.branch ? ` / ${context.branch}` : "";
33→  return `Browser - ${repo}${branch}`;
34→}
35→
36→export function useBrowserDetach(context: DetachedBrowserWorkspaceContext | null) {
37→  const isDetached = useBrowserWindowStore((s) => s.detachedWindowOpen);
38→
39→  const detach = useCallback(async () => {
40→    if (!context) return;
41→
42→    // Mark as detached before creating the window so the main UI updates immediately.
43→    browserWindowActions.setDetachedWindowOpen(context);
44→
45→    try {
46→      await native.browserViews.createDetachedWindow({
47→        url: buildDetachUrl(context),
48→        title: buildWindowTitle(context),
49→        width: 960,
50→        height: 700,
51→        minWidth: 820,
52→        minHeight: 560,
53→      });
54→
55→      await native.events.send(BROWSER_WORKSPACE_CHANGE, context);
56→    } catch (e) {
57→      console.error("[BrowserDetach] Failed to create detached window:", e);
58→      browserWindowActions.clearDetachedWindow();
59→    }
60→  }, [context]);
61→
62→  const reattach = useCallback(async () => {
63→    browserWindowActions.clearDetachedWindow();
64→
65→    // Close the detached window if it exists
66→    try {
67→      await native.browserViews.closeDetachedWindow();
68→    } catch {
69→      // Window may already be closed
70→    }
71→  }, []);
72→
73→  // When the user closes the detached OS window directly (via title bar X),
74→  // the main process sends "browser:detached-closed" — reset our store so
75→  // the main window UI reflects the reattached state.
76→  useEffect(() => {
77→    // native.events.on handles the capability check internally — no-op in web mode
78→    const unlisten = native.events.on("browser:detached-closed" as any, () => {
79→      browserWindowActions.clearDetachedWindow();
80→    });
81→
82→    return unlisten;
83→  }, []);
84→
85→  return { isDetached, detach, reattach };
86→}
