 5→/**
 6→ * Subscribe to a native IPC event. Returns unsubscribe function.
 7→ * In web mode, returns a no-op unsubscribe.
 8→ *
 9→ * Note: The returned cleanup function is synchronous, but the actual
10→ * listener registration is async (listen returns Promise<UnlistenFn>).
11→ * For React effects, call the returned fn in the cleanup. If the
12→ * listener hasn't resolved yet, it will be cleaned up when it does.
13→ */
14→export function on<K extends AppEventName>(
15→  event: K,
16→  callback: (data: AppEventMap[K]) => void
17→): () => void {
18→  if (!capabilities.ipcEventListeners) return () => {};
19→
20→  let cleanup: (() => void) | null = null;
21→  let cancelled = false;
22→
23→  // listen() returns Promise<UnlistenFn>
24→  listen(event, (e) => callback(e.payload as AppEventMap[K]))
25→    .then((unlisten) => {
26→      if (cancelled) {
27→        unlisten();
28→      } else {
29→        cleanup = unlisten;
30→      }
31→    })
32→    .catch(() => {});
33→
34→  return () => {
35→    cancelled = true;
36→    cleanup?.();
37→  };
38→}
39→
40→/**
41→ * Emit an event to the Electron main process (for cross-window relay).
42→ * No-op in web mode.
43→ */
44→export async function send<K extends AppEventName>(
45→  event: K,
46→  payload: AppEventMap[K]
47→): Promise<void> {
48→  if (!capabilities.ipcEventListeners) return;
49→  await emit(event, payload);
50→}
