 10→import { normalizeError, reportError } from "@/shared/utils/errorReporting";
 11→import { AppEventSchemaMap, type AppEventMap, type AppEventName } from "@shared/events";
 12→
 13→// Check if running in Electron environment (preload script exposes electronAPI)
 14→export const isElectronEnv = typeof window !== "undefined" && "electronAPI" in window;
 15→
 16→/**
 17→ * Invoke an Electron IPC command via the preload bridge.
 18→ * Falls back to error in non-Electron environments.
 19→ */
 20→export async function invoke<T = unknown>(
 21→  command: string,
 22→  args?: Record<string, unknown>
 23→): Promise<T> {
 24→  if (!isElectronEnv) {
 25→    console.warn(`[Platform] Electron invoke called in non-Electron environment: ${command}`);
 26→    throw new Error(`Electron command not available in web mode: ${command}`);
 27→  }
 28→
 29→  try {
 30→    return (await window.electronAPI!.invoke(command, args)) as T;
 31→  } catch (error) {
 32→    const normalized = normalizeError(error);
 33→    reportError(normalized, {
 34→      source: "electron.invoke",
 35→      action: command,
 36→      extra: { argsKeys: args ? Object.keys(args) : undefined },
 37→    });
 38→    throw normalized;
 39→  }
 40→}
