 42→/**
 43→ * Type-safe event listener for Electron IPC events.
 44→ *
 45→ * When called with a known event name from AppEventMap, the payload type
 46→ * is inferred automatically:
 47→ *
 48→ *   listen(WORKSPACE_PROGRESS, (e) => e.payload.workspaceId)
 49→ *
 50→ * Also accepts arbitrary event names with an explicit generic for backwards
 51→ * compat during incremental migration.
 52→ *
 53→ * Returns a Promise<UnlistenFn> for API consistency,
 54→ * even though Electron's IPC returns unsubscribe synchronously.
 55→ */
 56→export async function listen<K extends AppEventName>(
 57→  event: K,
 58→  handler: (event: { payload: AppEventMap[K] }) => void
 59→): Promise<() => void>;
 60→export async function listen<T>(
 61→  event: string,
 62→  handler: (event: { payload: T }) => void
 63→): Promise<() => void>;
 64→export async function listen(
 65→  event: string,
 66→  handler: (event: { payload: unknown }) => void
 67→): Promise<() => void> {
 68→  if (!isElectronEnv) {
 69→    console.warn(`[Platform] Electron listen called in non-Electron environment: ${event}`);
 70→    return () => {};
 71→  }
 72→
 73→  const schema = (AppEventSchemaMap as Record<string, import("zod").ZodTypeAny>)[event];
 74→
 75→  // Register via preload bridge — electronAPI.on returns a sync unsubscribe fn.
 76→  // We wrap the callback to match the { payload } shape expected by consumers.
 77→  const unlisten = window.electronAPI!.on(event, (...args: unknown[]) => {
 78→    // Electron IPC sends payload as the first arg after the stripped IpcRendererEvent
 79→    const payload = args[0];
 80→
 81→    if (!schema) {
 82→      // Unknown event (not in AppEventMap) — pass through without validation
 83→      handler({ payload });
 84→      return;
 85→    }
 86→
 87→    const result = schema.safeParse(payload);
 88→    if (!result.success) {
 89→      console.error(
 90→        `[Platform] Event "${event}" payload failed schema validation:`,
 91→        result.error.format()
 92→      );
 93→      // Still deliver the original payload so the app doesn't break
 94→      handler({ payload });
 95→      return;
 96→    }
 97→    // Pass validated + stripped payload (extra keys removed by Zod)
 98→    handler({ payload: result.data });
 99→  });
100→
101→  return unlisten;
102→}
103→
104→/**
105→ * Emit an event (send to main process, which can broadcast to all windows)
106→ */
107→export async function emit<T>(event: string, payload?: T): Promise<void> {
108→  if (!isElectronEnv) {
109→    console.warn(`[Platform] Electron emit called in non-Electron environment: ${event}`);
110→    return;
111→  }
112→
113→  window.electronAPI!.send(event, payload);
114→}
115→
116→/**
117→ * Check if Electron APIs are available (function version of isElectronEnv)
118→ */
119→export function isElectronAvailable(): boolean {
120→  return isElectronEnv;
121→}
