 55→/**
 56→ * Play a visual cursor effect (move+ripple or pin) and wait for its
 57→ * animation duration. Non-critical — silently swallows errors so the
 58→ * actual browser action always proceeds.
 59→ */
 60→async function playCursorEffect(label: string, effectJs: string): Promise<void> {
 61→  try {
 62→    const result = await evalWithResult(label, effectJs, 3000);
 63→    const parsed = safeParseWebviewJson<{ duration?: number }>(result);
 64→    if (parsed.duration && parsed.duration > 0)
 65→      await new Promise((r) => setTimeout(r, parsed.duration));
 66→  } catch {
 67→    /* visual effects are non-critical */
 68→  }
 69→}
