 71→/**
 72→ * Waits for the `browser:page-load` IPC event with event="finished"
 73→ * for the given webview label. This is emitted by Electron's `did-finish-load`
 74→ * callback — no polling needed.
 75→ *
 76→ * When `alsoListenUrlChange` is true (for history.back() in SPAs), also
 77→ * resolves on `browser:url-change` since SPA routers don't trigger a
 78→ * real page load — they fire popstate which emits url-change instead.
 79→ *
 80→ * After the page finishes loading, waits a short DOM-settle delay so
 81→ * frameworks (React, Next.js, etc.) can hydrate before we snapshot.
 82→ */
 83→async function waitForPageLoad(
 84→  label: string,
 85→  timeoutMs = 15_000,
 86→  settleMs = 500,
 87→  alsoListenUrlChange = false
 88→): Promise<string> {
 89→  return new Promise<string>((resolve, reject) => {
 90→    let settled = false;
 91→    const unlistenFns: (() => void)[] = [];
 92→
 93→    function cleanup() {
 94→      for (const fn of unlistenFns) fn();
 95→    }
 96→
 97→    const timer = setTimeout(() => {
 98→      if (!settled) {
 99→        settled = true;
100→        cleanup();
101→        reject(new Error(`Page did not finish loading within ${timeoutMs}ms`));
102→      }
103→    }, timeoutMs);
104→
105→    function onLoad(url: string) {
106→      if (!settled) {
107→        settled = true;
108→        clearTimeout(timer);
109→        cleanup();
110→        // Short settle for framework hydration (React, Next.js, etc.)
111→        setTimeout(() => resolve(url), settleMs);
112→      }
113→    }
114→
115→    // Primary: browser:page-load (real navigations)
116→    const unlistenPageLoad = native.events.on(BROWSER_PAGE_LOAD, (data) => {
117→      const payload = data as { label: string; event: string; url: string };
118→      if (payload.label === label && payload.event === "finished") {
119→        onLoad(payload.url);
120→      }
121→    });
122→    unlistenFns.push(unlistenPageLoad);
123→
124→    // Secondary: browser:url-change (SPA navigations via popstate)
125→    if (alsoListenUrlChange) {
126→      const unlistenUrlChange = native.events.on(BROWSER_URL_CHANGE, (data) => {
127→        const payload = data as { label: string; url: string };
128→        if (payload.label === label) {
129→          onLoad(payload.url);
130→        }
131→      });
132→      unlistenFns.push(unlistenUrlChange);
133→    }
134→  });
135→}
