137→// ---- Response helper type ----
138→
139→/** Response function for tool request handlers. */
140→type RespondFn = (result: unknown) => void;
141→
142→/**
143→ * Hook that handles browser automation RPC requests from the sidecar.
144→ *
145→ * Listens for WS tool requests (via `useWsToolRequest`), dispatches to the appropriate
146→ * handler based on method name, and sends JSON-RPC responses back to the sidecar.
147→ *
148→ * @param getActiveTab - Function to get the current active browser tab state
149→ * @param onAutoCreateTab - Optional callback to auto-create a browser tab when
150→ *   BrowserNavigate is called with no existing tab. Returns the new webviewLabel
151→ *   or null if creation failed. Navigate auto-creates a tab if none exists.
152→ * @param getTabs - Optional function to get all browser tabs for session-mapped lookups
153→ */
154→export function useBrowserRpcHandler(
155→  getActiveTab: () => BrowserTabState | null,
156→  onAutoCreateTab?: (url: string) => string | null,
157→  workspaceId?: string | null,
158→  getTabs?: () => BrowserTabState[]
159→) {
160→  const getActiveTabRef = useRef(getActiveTab);
161→  const getTabsRef = useRef(getTabs);
162→  const onAutoCreateTabRef = useRef(onAutoCreateTab);
163→
164→  useEffect(() => {
165→    getActiveTabRef.current = getActiveTab;
166→  }, [getActiveTab]);
167→
168→  useEffect(() => {
169→    getTabsRef.current = getTabs;
170→  }, [getTabs]);
171→
172→  useEffect(() => {
173→    onAutoCreateTabRef.current = onAutoCreateTab;
174→  }, [onAutoCreateTab]);
175→
176→  // Guard against rapid duplicate auto-create calls
177→  const autoCreatePendingRef = useRef<string | null>(null);
178→
179→  // Session → webviewLabel mapping for multi-agent tab isolation.
180→  // Each session (agent) navigates to its own tab; subsequent operations
181→  // (snapshot, click, type, waitFor) target that session's tab automatically.
182→  const sessionTabMapRef = useRef(new Map<string, string>());
183→
184→  // Clear session→tab map on workspace switch
185→  const prevWorkspaceIdRef = useRef(workspaceId);
186→  useEffect(() => {
187→    if (prevWorkspaceIdRef.current === workspaceId) return;
188→    sessionTabMapRef.current.clear();
189→    autoCreatePendingRef.current = null;
190→    prevWorkspaceIdRef.current = workspaceId;
191→  }, [workspaceId]);
192→
193→  const resolveWebviewLabel = useCallback(
194→    (requestedLabel?: string, sessionId?: string): string | null => {
195→      if (requestedLabel) return requestedLabel;
196→      // Check session→tab mapping first (multi-agent isolation)
197→      if (sessionId) {
198→        const mapped = sessionTabMapRef.current.get(sessionId);
199→        if (mapped) return mapped;
200→      }
201→      const tab = getActiveTabRef.current();
202→      return tab?.webviewLabel ?? null;
203→    },
204→    []
205→  );
206→
207→  const handleBrowserSnapshot = useCallback(
208→    async (params: Record<string, unknown>, respond: RespondFn) => {
209→      const label = resolveWebviewLabel(
210→        params.webviewLabel as string | undefined,
211→        params.sessionId as string | undefined
212→      );
213→      if (!label) {
214→        respond({ error: "No active browser tab" });
215→        return;
216→      }
217→
218→      try {
219→        // Visual feedback: scan-line to show the AI is reading the page (best-effort, fire-and-forget)
220→        native.browserViews.evaluate(label, SCAN_PAGE_JS).catch(() => {});
221→
222→        // Heavy pages (e.g. portals) can have 10k+ DOM nodes — the
223→        // accessibility tree builder needs more time than the default 8s.
224→        const t0 = Date.now();
225→        const resultStr = await evalWithResult(label, SNAPSHOT_JS, 15_000);
226→        const result = safeParseWebviewJson(resultStr);
227→        console.log(`[BrowserRPC] Snapshot completed in ${Date.now() - t0}ms`);
228→        respond(result);
229→      } catch (err: unknown) {
230→        // Clear stale session mapping so next BrowserNavigate triggers auto-create
231→        const msg = getErrorMessage(err);
232→        if (msg.includes("not found") && params.sessionId) {
233→          sessionTabMapRef.current.delete(params.sessionId as string);
234→        }
235→        console.error(`[BrowserRPC] Snapshot failed:`, msg);
236→        respond({
237→          error: msg.includes("not found")
238→            ? "Browser tab not found. Use BrowserNavigate to open a page first."
239→            : msg,
240→        });
241→      }
242→    },
243→    [resolveWebviewLabel]
244→  );
245→
246→  const handleBrowserClick = useCallback(
247→    async (params: Record<string, unknown>, respond: RespondFn) => {
248→      const label = resolveWebviewLabel(
249→        params.webviewLabel as string | undefined,
250→        params.sessionId as string | undefined
251→      );
252→      if (!label) {
253→        respond({ success: false, error: "No active browser tab" });
254→        return;
255→      }
256→
257→      const ref = params.ref as string;
258→      const doubleClick = params.doubleClick as boolean | undefined;
259→      if (!ref) {
260→        respond({ success: false, error: "Missing ref parameter" });
261→        return;
262→      }
263→
264→      try {
265→        await playCursorEffect(label, buildMoveCursorAndRippleJs(ref));
266→
267→        const js = buildClickJs(ref, doubleClick);
268→        const resultStr = await evalWithResult(label, js);
