388→            respond({
389→              success: true,
390→              webviewLabel: label,
391→              snapshot: `Page loaded but snapshot failed: ${snapMsg}. Use BrowserSnapshot to retry.`,
392→            });
393→          }
394→        } catch (err: unknown) {
395→          autoCreatePendingRef.current = null;
396→          const msg = getErrorMessage(err);
