415→        const loadedUrl = await waitForPageLoad(label);
416→        console.log(
417→          `[BrowserRPC] Navigate (existing tab) → page loaded in ${Date.now() - t0}ms: ${loadedUrl}`
418→        );
419→        // Take a snapshot (best-effort — heavy pages may timeout)
420→        try {
