422→          const result = safeParseWebviewJson(resultStr);
423→          respond({ success: true, webviewLabel: label, ...result });
424→        } catch (snapErr: unknown) {
425→          const snapMsg = getErrorMessage(snapErr);
426→          console.warn(`[BrowserRPC] Post-navigate snapshot failed: ${snapMsg}`);
427→          respond({
428→            success: true,
429→            webviewLabel: label,
430→            snapshot: `Page loaded but snapshot failed: ${snapMsg}. Use BrowserSnapshot to retry.`,
431→          });
432→        }
433→      } catch (err: unknown) {
