698→        respond({ success: false, error: "Missing ref or values parameter" });
699→        return;
700→      }
701→
702→      try {
703→        await playCursorEffect(label, buildMoveCursorAndRippleJs(ref));
704→
705→        const js = buildSelectOptionJs(ref, values);
706→        const resultStr = await evalWithResult(label, js);
707→        const result = safeParseWebviewJson(resultStr);
708→
709→        // Fade cursor out gracefully after select (dwell 600ms then fade)
710→        native.browserViews.evaluate(label, buildFadeCursorJs()).catch(() => {});
711→
712→        respond(result);
713→      } catch (err: unknown) {
714→        respond({ success: false, error: getErrorMessage(err) });
715→      }
716→    },
717→    [resolveWebviewLabel]
718→  );
719→
720→  const handleBrowserNavigateBack = useCallback(
721→    async (params: Record<string, unknown>, respond: RespondFn) => {
722→      const label = resolveWebviewLabel(
723→        params.webviewLabel as string | undefined,
724→        params.sessionId as string | undefined
725→      );
726→      if (!label) {
727→        respond({ success: false, error: "No active browser tab" });
728→        return;
729→      }
730→
731→      try {
732→        const t0 = Date.now();
733→        // Execute history.back() in the webview
734→        await native.browserViews.evaluate(label, "history.back();");
735→        // Wait for page load OR SPA url-change (SPAs don't trigger real page loads)
736→        const loadedUrl = await waitForPageLoad(label, 15_000, 500, true);
737→        console.log(
738→          `[BrowserRPC] NavigateBack → page loaded in ${Date.now() - t0}ms: ${loadedUrl}`
739→        );
740→        // Take a snapshot of the new page
741→        try {
742→          const resultStr = await evalWithResult(label, SNAPSHOT_JS, 12_000);
743→          const result = safeParseWebviewJson(resultStr);
744→          respond({ success: true, ...result });
745→        } catch (snapErr: unknown) {
746→          const snapMsg = getErrorMessage(snapErr);
747→          console.warn(`[BrowserRPC] Post-navigateBack snapshot failed: ${snapMsg}`);
748→          respond({
749→            success: true,
750→            snapshot: `Navigated back but snapshot failed: ${snapMsg}. Use BrowserSnapshot to retry.`,
751→          });
752→        }
753→      } catch (err: unknown) {
754→        const msg = getErrorMessage(err);
755→        console.error(`[BrowserRPC] NavigateBack failed:`, msg);
756→        respond({ success: false, error: msg });
757→      }
758→    },
759→    [resolveWebviewLabel]
760→  );
761→
762→  const handleBrowserConsoleMessages = useCallback(
763→    async (params: Record<string, unknown>, respond: RespondFn) => {
764→      const label = resolveWebviewLabel(
765→        params.webviewLabel as string | undefined,
766→        params.sessionId as string | undefined
767→      );
768→      if (!label) {
769→        respond({ logs: "", count: 0, error: "No active browser tab" });
770→        return;
771→      }
772→
773→      try {
774→        const resultStr = await evalWithResult(label, CONSOLE_MESSAGES_JS);
775→        const result = safeParseWebviewJson(resultStr);
776→        respond(result);
777→      } catch (err: unknown) {
778→        respond({ logs: "", count: 0, error: getErrorMessage(err) });
779→      }
780→    },
781→    [resolveWebviewLabel]
782→  );
783→
784→  const handleBrowserScreenshot = useCallback(
785→    async (params: Record<string, unknown>, respond: RespondFn) => {
786→      const label = resolveWebviewLabel(
787→        params.webviewLabel as string | undefined,
788→        params.sessionId as string | undefined
789→      );
790→      if (!label) {
791→        respond({ image: "", error: "No active browser tab" });
792→        return;
793→      }
794→
795→      try {
796→        // Build optional crop rect for screenshot command
797→        const rect = params.rect as
798→          | { x: number; y: number; width: number; height: number }
799→          | undefined;
800→        const screenshotOpts: Record<string, unknown> = {};
801→        if (rect) {
802→          screenshotOpts.rectX = rect.x;
803→          screenshotOpts.rectY = rect.y;
804→          screenshotOpts.rectWidth = rect.width;
805→          screenshotOpts.rectHeight = rect.height;
806→        }
807→
808→        // Call the native screenshot command (Electron BrowserView.capturePage)
809→        const base64 = await native.browserViews.screenshot(label, screenshotOpts);
810→
811→        // Visual feedback: camera flash effect AFTER capture (so it doesn't appear in the image)
812→        native.browserViews
813→          .evaluate(label, buildScreenshotFlashJs(rect ?? undefined))
814→          .catch(() => {});
815→        // Best-effort URL + title for context
816→        const url = await native.browserViews.getUrl(label);
817→        respond({ image: base64, url, title: "" });
818→      } catch (err: unknown) {
819→        // Clear stale session mapping so next BrowserNavigate triggers auto-create
820→        const msg = getErrorMessage(err);
821→        if (msg.includes("not found") && params.sessionId) {
822→          sessionTabMapRef.current.delete(params.sessionId as string);
823→        }
824→        respond({
825→          image: "",
826→          error: msg.includes("not found")
827→            ? "Browser tab not found. Use BrowserNavigate to open a page first."
828→            : msg,
829→        });
830→      }
831→    },
832→    [resolveWebviewLabel]
833→  );
834→
835→  const handleBrowserNetworkRequests = useCallback(
836→    async (params: Record<string, unknown>, respond: RespondFn) => {
837→      const label = resolveWebviewLabel(
838→        params.webviewLabel as string | undefined,
839→        params.sessionId as string | undefined
840→      );
841→      if (!label) {
842→        respond({ requests: "", count: 0, error: "No active browser tab" });
843→        return;
844→      }
845→
846→      try {
847→        const resultStr = await evalWithResult(label, NETWORK_REQUESTS_JS);
848→        const result = safeParseWebviewJson(resultStr);
849→        respond(result);
850→      } catch (err: unknown) {
851→        respond({ requests: "", count: 0, error: getErrorMessage(err) });
852→      }
853→    },
854→    [resolveWebviewLabel]
855→  );
856→
857→  const handleBrowserScroll = useCallback(
858→    async (params: Record<string, unknown>, respond: RespondFn) => {
859→      const label = resolveWebviewLabel(
860→        params.webviewLabel as string | undefined,
861→        params.sessionId as string | undefined
862→      );
863→      if (!label) {
864→        respond({ success: false, error: "No active browser tab" });
865→        return;
866→      }
867→
868→      const direction = params.direction as string | undefined;
869→      const amount = params.amount as number | undefined;
870→      const ref = params.ref as string | undefined;
871→
872→      try {
873→        const js = buildScrollJs(direction, amount, ref);
874→        const resultStr = await evalWithResult(label, js);
875→        const result = safeParseWebviewJson(resultStr);
876→        respond(result);
877→      } catch (err: unknown) {
878→        respond({ success: false, error: getErrorMessage(err) });
879→      }
880→    },
881→    [resolveWebviewLabel]
882→  );
883→
884→  // ============================================================================
885→  // Dispatch helper
886→  // ============================================================================
887→
888→  const dispatchBrowserMethod = useCallback(
889→    (
890→      method: string,
891→      params: Record<string, unknown>,
892→      respond: RespondFn,
893→      respondError?: (error: string) => void
894→    ) => {
895→      match(method)
896→        .with("browserSnapshot", () => handleBrowserSnapshot(params, respond))
897→        .with("browserClick", () => handleBrowserClick(params, respond))
898→        .with("browserType", () => handleBrowserType(params, respond))
899→        .with("browserNavigate", () => handleBrowserNavigate(params, respond))
900→        .with("browserGetState", () => handleBrowserGetState(params, respond))
901→        .with("browserWaitFor", () => handleBrowserWaitFor(params, respond))
902→        .with("browserEvaluate", () => handleBrowserEvaluate(params, respond))
903→        .with("browserPressKey", () => handleBrowserPressKey(params, respond))
904→        .with("browserHover", () => handleBrowserHover(params, respond))
905→        .with("browserSelectOption", () => handleBrowserSelectOption(params, respond))
906→        .with("browserNavigateBack", () => handleBrowserNavigateBack(params, respond))
907→        .with("browserConsoleMessages", () => handleBrowserConsoleMessages(params, respond))
908→        .with("browserNetworkRequests", () => handleBrowserNetworkRequests(params, respond))
909→        .with("browserScreenshot", () => handleBrowserScreenshot(params, respond))
910→        .with("browserScroll", () => handleBrowserScroll(params, respond))
911→        .otherwise(() => {
912→          if (method.startsWith("browser") && respondError) {
913→            respondError(`Unknown browser method: ${method}`);
914→          }
915→        });
916→    },
917→    [
918→      handleBrowserSnapshot,
919→      handleBrowserClick,
920→      handleBrowserType,
921→      handleBrowserNavigate,
922→      handleBrowserGetState,
923→      handleBrowserWaitFor,
924→      handleBrowserEvaluate,
925→      handleBrowserPressKey,
926→      handleBrowserHover,
927→      handleBrowserSelectOption,
928→      handleBrowserNavigateBack,
929→      handleBrowserConsoleMessages,
930→      handleBrowserNetworkRequests,
931→      handleBrowserScreenshot,
932→      handleBrowserScroll,
933→    ]
934→  );
935→
936→  // ============================================================================
937→  // WS event listener (agent-server → backend → q:event tool:request)
938→  // ============================================================================
939→
940→  useWsToolRequest((method, requestId, params, respond, respondError) => {
941→    if (import.meta.env.DEV) {
942→      console.log("[BrowserRPC] Received request (WS):", method, "requestId:", requestId);
943→    }
944→
945→    dispatchBrowserMethod(method, params, respond, respondError);
946→  });
947→}
