  1→/**
  2→ * BrowserView Manager
  3→ *
  4→ * Manages Electron BrowserViews for the agent browser automation feature.
  5→ * Uses native Electron BrowserView APIs for cross-platform web automation.
  6→ *
  7→ * Each browser view gets:
  8→ * - Its own session partition (isolated cookies/storage)
  9→ * - A preload script for console capture
 10→ * - Event forwarding (page-load, title, url, navigation)
 11→ * - Network request tracking via session.webRequest
 12→ *
 13→ * Handler names match the snake_case names the renderer calls
 14→ * via invoke(). The preload's browserInvoke() uses "browser:" prefixed names
 15→ * for its own methods, but generic invoke() calls use snake_case.
 16→ */
 17→
 18→import { BrowserView, BrowserWindow, ipcMain, shell } from "electron";
 19→import { join } from "path";
 20→import { is } from "@electron-toolkit/utils";
 21→
 22→const views = new Map<string, BrowserView>();
 23→const viewBounds = new Map<string, Electron.Rectangle>();
 24→
 25→/** Reference to the detached browser window (only one at a time) */
 26→let detachedWindow: BrowserWindow | null = null;
 27→
 28→export function registerBrowserViewHandlers(): void {
 29→  // -------------------------------------------------------------------------
 30→  // Create a new browser view
 31→  // Renderer calls: invoke("create_browser_webview", { label, url, x, y, width, height, windowLabel })
 32→  // -------------------------------------------------------------------------
 33→
 34→  ipcMain.handle(
 35→    "create_browser_webview",
 36→    (
 37→      _e,
 38→      {
 39→        label,
 40→        url,
 41→        x,
 42→        y,
 43→        width,
 44→        height,
 45→      }: {
 46→        label: string;
 47→        url: string;
 48→        x: number;
 49→        y: number;
 50→        width: number;
 51→        height: number;
 52→        windowLabel?: string;
 53→      }
 54→    ) => {
 55→      const mainWindow = BrowserWindow.getAllWindows()[0];
 56→      if (!mainWindow) return;
 57→
 58→      // Clean up existing view with same label
 59→      const existing = views.get(label);
 60→      if (existing) {
 61→        mainWindow.removeBrowserView(existing);
 62→        (existing.webContents as any).destroy?.();
 63→        views.delete(label);
 64→      }
 65→
 66→      const bounds = {
 67→        x: Math.round(x),
 68→        y: Math.round(y),
 69→        width: Math.round(Math.max(width, 100)),
 70→        height: Math.round(Math.max(height, 100)),
 71→      };
 72→
 73→      const view = new BrowserView({
 74→        webPreferences: {
 75→          partition: `persist:browser-${label}`,
 76→          contextIsolation: true,
 77→          sandbox: true,
 78→          preload: join(__dirname, "../preload/browser-preload.mjs"),
 79→        },
 80→      });
 81→
 82→      mainWindow.addBrowserView(view);
 83→      view.setBounds(bounds);
 84→      view.setAutoResize({ width: false, height: false });
 85→      view.webContents.loadURL(url);
 86→      views.set(label, view);
 87→
 88→      // Forward navigation events to renderer
 89→      view.webContents.on("did-start-loading", () => {
 90→        mainWindow.webContents.send("browser:page-load", {
 91→          label,
 92→          url: view.webContents.getURL(),
 93→          event: "started",
 94→        });
 95→      });
 96→
 97→      view.webContents.on("did-finish-load", () => {
 98→        mainWindow.webContents.send("browser:page-load", {
 99→          label,
100→          url: view.webContents.getURL(),
101→          event: "finished",
102→        });
103→      });
104→
105→      view.webContents.on("did-fail-load", (_event, errorCode, errorDescription) => {
106→        mainWindow.webContents.send("browser:page-load", {
107→          label,
108→          url: view.webContents.getURL(),
109→          event: "failed",
110→          error: { code: errorCode, description: errorDescription },
111→        });
112→      });
113→
114→      view.webContents.on("page-title-updated", (_, title) => {
115→        mainWindow.webContents.send("browser:title-changed", { label, title });
116→      });
117→
118→      view.webContents.on("did-navigate", () => {
119→        mainWindow.webContents.send("browser:url-change", {
120→          label,
121→          url: view.webContents.getURL(),
122→        });
123→      });
124→
125→      view.webContents.on("did-navigate-in-page", () => {
126→        mainWindow.webContents.send("browser:url-change", {
127→          label,
128→          url: view.webContents.getURL(),
129→        });
130→      });
131→
132→      // TODO: Network request tracking — disabled until renderer listener is wired.
133→      // The events were being sent but nothing consumed them (wasted IPC traffic).
134→
135→      // Open external links in system browser (only allow http/https)
136→      view.webContents.setWindowOpenHandler(({ url: linkUrl }) => {
137→        try {
138→          const parsed = new URL(linkUrl);
139→          if (parsed.protocol === "http:" || parsed.protocol === "https:") {
140→            shell.openExternal(linkUrl);
141→          }
142→        } catch {
143→          // Ignore malformed URLs
144→        }
145→        return { action: "deny" };
146→      });
147→    }
148→  );
149→
150→  // -------------------------------------------------------------------------
151→  // Navigation
152→  // Renderer calls: invoke("navigate_browser_webview", { label, url })
153→  // -------------------------------------------------------------------------
154→
155→  ipcMain.handle(
156→    "navigate_browser_webview",
157→    (_e, { label, url }: { label: string; url: string }) => {
158→      views.get(label)?.webContents.loadURL(url);
159→    }
160→  );
161→
162→  // -------------------------------------------------------------------------
163→  // JavaScript evaluation
164→  // Renderer calls: invoke("eval_browser_webview", { label, js })
165→  // Returns the result of the JS execution (used by eval-with-result.ts)
166→  // -------------------------------------------------------------------------
167→
168→  ipcMain.handle(
169→    "eval_browser_webview",
170→    async (_e, { label, js }: { label: string; js: string }) => {
171→      const view = views.get(label);
172→      if (!view) return null;
173→      try {
174→        return await view.webContents.executeJavaScript(js);
175→      } catch (err) {
176→        console.error(`[browser:eval] Error in view "${label}":`, err);
177→        return null;
178→      }
179→    }
180→  );
181→
182→  // -------------------------------------------------------------------------
183→  // JavaScript evaluation (alias)
184→  // Renderer calls: invoke("eval_browser_webview_with_result", { label, js })
185→  // Same operation as eval_browser_webview — executeJavaScript already returns a result.
186→  // Both names are used by renderer code (BrowserTab.tsx uses this variant).
187→  // -------------------------------------------------------------------------
188→
189→  ipcMain.handle(
190→    "eval_browser_webview_with_result",
191→    async (_e, { label, js }: { label: string; js: string }) => {
192→      const view = views.get(label);
193→      if (!view) return null;
194→      try {
195→        return await view.webContents.executeJavaScript(js);
196→      } catch (err) {
197→        console.error(`[BrowserView] eval failed for "${label}":`, err);
198→        return null;
199→      }
200→    }
201→  );
202→
203→  // -------------------------------------------------------------------------
204→  // Get URL (snake_case variant)
205→  // Renderer calls: invoke("get_browser_webview_url", { label })
206→  // Used by useBrowserRpcHandler.ts for URL queries.
207→  // -------------------------------------------------------------------------
208→
209→  ipcMain.handle("get_browser_webview_url", (_e, { label }: { label: string }) => {
210→    const view = views.get(label);
211→    return view ? view.webContents.getURL() : "";
212→  });
213→
214→  // -------------------------------------------------------------------------
215→  // Screenshot
216→  // Renderer calls: invoke("screenshot_browser_webview", { label, x?, y?, width?, height? })
217→  // Supports optional crop rectangle; omit for full page capture.
218→  // -------------------------------------------------------------------------
219→
220→  ipcMain.handle(
221→    "screenshot_browser_webview",
222→    async (
223→      _e,
224→      {
225→        label,
226→        x,
227→        y,
228→        width,
229→        height,
230→      }: {
231→        label: string;
232→        x?: number;
233→        y?: number;
234→        width?: number;
235→        height?: number;
236→      }
237→    ) => {
238→      const view = views.get(label);
239→      if (!view) return null;
240→      try {
241→        let image;
242→        if (x !== undefined && y !== undefined && width !== undefined && height !== undefined) {
243→          image = await view.webContents.capturePage({
244→            x: Math.round(x),
245→            y: Math.round(y),
246→            width: Math.round(width),
247→            height: Math.round(height),
248→          });
249→        } else {
250→          image = await view.webContents.capturePage();
251→        }
252→        return image.toDataURL();
253→      } catch (err) {
254→        console.error(`[BrowserView] screenshot failed for "${label}":`, err);
255→        return null;
256→      }
257→    }
258→  );
259→
260→  // -------------------------------------------------------------------------
261→  // DevTools
262→  // Renderer calls: invoke("open_browser_devtools", { label })
263→  //                 invoke("close_browser_devtools", { label })
264→  // -------------------------------------------------------------------------
265→
266→  ipcMain.handle("open_browser_devtools", (_e, { label }: { label: string }) => {
267→    views.get(label)?.webContents.openDevTools({ mode: "detach" });
268→  });
269→
270→  ipcMain.handle("close_browser_devtools", (_e, { label }: { label: string }) => {
271→    const view = views.get(label);
272→    if (view?.webContents.isDevToolsOpened()) {
273→      view.webContents.closeDevTools();
274→    }
275→  });
276→
277→  // -------------------------------------------------------------------------
278→  // Bounds / visibility
279→  // Renderer calls: invoke("set_browser_webview_bounds", { label, x, y, width, height })
280→  //                 invoke("show_browser_webview", { label })
281→  //                 invoke("hide_browser_webview", { label })
282→  //                 invoke("close_browser_webview", { label })
283→  //                 invoke("reload_browser_webview", { label })
284→  // -------------------------------------------------------------------------
285→
286→  ipcMain.handle(
287→    "set_browser_webview_bounds",
288→    (
289→      _e,
290→      {
291→        label,
292→        x,
293→        y,
294→        width,
295→        height,
296→      }: {
297→        label: string;
298→        x: number;
299→        y: number;
300→        width: number;
301→        height: number;
302→      }
303→    ) => {
304→      views.get(label)?.setBounds({
305→        x: Math.round(x),
306→        y: Math.round(y),
307→        width: Math.round(width),
308→        height: Math.round(height),
309→      });
310→    }
311→  );
312→
313→  ipcMain.handle("show_browser_webview", (_e, { label }: { label: string }) => {
314→    const mainWindow = BrowserWindow.getAllWindows()[0];
315→    const view = views.get(label);
316→    if (mainWindow && view) {
317→      // Re-add if it was removed (hidden)
318→      if (!mainWindow.getBrowserViews().includes(view)) {
319→        mainWindow.addBrowserView(view);
320→      }
321→      const savedBounds = viewBounds.get(label);
322→      if (savedBounds) {
323→        view.setBounds(savedBounds);
324→      }
325→    }
326→  });
327→
328→  ipcMain.handle("hide_browser_webview", (_e, { label }: { label: string }) => {
329→    const view = views.get(label);
330→    if (view) {
331→      viewBounds.set(label, view.getBounds());
332→      view.setBounds({ x: 0, y: 0, width: 0, height: 0 });
333→    }
334→  });
335→
336→  ipcMain.handle("close_browser_webview", (_e, { label }: { label: string }) => {
337→    const view = views.get(label);
338→    if (!view) return;
339→    const mainWindow = BrowserWindow.getAllWindows()[0];
340→    if (mainWindow) {
341→      mainWindow.removeBrowserView(view);
342→    }
343→    (view.webContents as any).destroy?.();
344→    views.delete(label);
345→    viewBounds.delete(label);
346→  });
347→
348→  ipcMain.handle("reload_browser_webview", (_e, { label }: { label: string }) => {
349→    views.get(label)?.webContents.reload();
350→  });
351→
352→  // -------------------------------------------------------------------------
353→  // Cookie management (preload browserInvoke calls "browser:cookies:set/get")
354→  // Keep these with the browser: prefix for the preload's browserInvoke()
355→  // -------------------------------------------------------------------------
356→
357→  ipcMain.handle(
358→    "browser:cookies:set",
359→    async (_e, { label, cookies }: { label: string; cookies: Electron.CookiesSetDetails[] }) => {
360→      const ses = views.get(label)?.webContents.session;
361→      if (!ses) return;
362→      for (const cookie of cookies) {
363→        await ses.cookies.set(cookie);
364→      }
365→    }
366→  );
367→
368→  ipcMain.handle(
369→    "browser:cookies:get",
370→    async (_e, { label, url }: { label: string; url: string }) => {
371→      const ses = views.get(label)?.webContents.session;
372→      if (!ses) return [];
373→      return ses.cookies.get({ url });
374→    }
375→  );
376→
377→  // -------------------------------------------------------------------------
378→  // Console message capture (preload browserInvoke calls "browser:getConsoleMessages")
379→  // -------------------------------------------------------------------------
380→
381→  ipcMain.handle("browser:getConsoleMessages", (_e, { label }: { label: string }) => {
382→    const view = views.get(label);
383→    if (!view) return [];
384→    return []; // TODO: buffer recent messages from preload forwarding
385→  });
386→
387→  // -------------------------------------------------------------------------
388→  // Get URL / title (preload browserInvoke calls "browser:getURL" / "browser:getTitle")
389→  // -------------------------------------------------------------------------
390→
391→  ipcMain.handle("browser:getURL", (_e, { label }: { label: string }) => {
392→    return views.get(label)?.webContents.getURL() ?? null;
393→  });
394→
395→  ipcMain.handle("browser:getTitle", (_e, { label }: { label: string }) => {
396→    return views.get(label)?.webContents.getTitle() ?? null;
397→  });
398→
399→  // -------------------------------------------------------------------------
400→  // Back / Forward (preload browserInvoke calls "browser:back" / "browser:forward")
401→  // -------------------------------------------------------------------------
402→
403→  ipcMain.handle("browser:back", (_e, { label }: { label: string }) => {
404→    const view = views.get(label);
405→    if (view?.webContents.canGoBack()) {
406→      view.webContents.goBack();
407→    }
408→  });
409→
410→  ipcMain.handle("browser:forward", (_e, { label }: { label: string }) => {
411→    const view = views.get(label);
412→    if (view?.webContents.canGoForward()) {
413→      view.webContents.goForward();
414→    }
415→  });
416→
417→  // -------------------------------------------------------------------------
418→  // Detached Browser Window
419→  // Renderer calls: invoke("browser:createDetachedWindow", { url, title, width, height, minWidth, minHeight })
420→  //                 invoke("browser:closeDetachedWindow")
421→  // -------------------------------------------------------------------------
422→
423→  ipcMain.handle(
424→    "browser:createDetachedWindow",
425→    (
426→      _e,
427→      {
428→        url,
429→        title,
430→        width,
431→        height,
432→        minWidth,
433→        minHeight,
434→      }: {
435→        url: string;
436→        title: string;
437→        width: number;
438→        height: number;
439→        minWidth?: number;
440→        minHeight?: number;
441→      }
442→    ) => {
443→      // Close existing detached window if any
444→      if (detachedWindow && !detachedWindow.isDestroyed()) {
445→        detachedWindow.close();
446→        detachedWindow = null;
447→      }
448→
449→      detachedWindow = new BrowserWindow({
450→        width,
451→        height,
452→        minWidth: minWidth ?? 600,
453→        minHeight: minHeight ?? 400,
454→        title,
455→        titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",
456→        trafficLightPosition: { x: 16, y: 18 },
457→        webPreferences: {
458→          preload: join(__dirname, "../preload/index.mjs"),
459→          contextIsolation: true,
460→          nodeIntegration: false,
461→          sandbox: false, // ESM preload (index.mjs) requires sandbox: false
462→        },
463→      });
464→
465→      // Load the renderer app with the detached window URL
466→      if (is.dev && process.env.ELECTRON_RENDERER_URL) {
467→        detachedWindow.loadURL(`${process.env.ELECTRON_RENDERER_URL}${url}`);
468→      } else {
469→        detachedWindow.loadFile(join(__dirname, "../renderer/index.html"), {
470→          search: url.includes("?") ? url.split("?")[1] : "",
471→        });
472→      }
473→
474→      detachedWindow.on("closed", () => {
475→        detachedWindow = null;
476→        // Notify the main renderer that the detached window was closed
477→        const mainWindow = BrowserWindow.getAllWindows()[0];
478→        if (mainWindow) {
479→          mainWindow.webContents.send("browser:detached-closed");
480→        }
481→      });
482→    }
483→  );
484→
485→  ipcMain.handle("browser:closeDetachedWindow", () => {
486→    if (detachedWindow && !detachedWindow.isDestroyed()) {
487→      detachedWindow.close();
488→      detachedWindow = null;
489→    }
490→  });
491→}
492→
493→/**
494→ * Clean up all browser views. Called on app quit.
495→ */
496→export function destroyAllBrowserViews(): void {
497→  const mainWindow = BrowserWindow.getAllWindows()[0];
498→  for (const [, view] of views) {
499→    if (mainWindow) {
500→      mainWindow.removeBrowserView(view);
501→    }
502→    (view.webContents as any).destroy?.();
503→  }
504→  views.clear();
505→
506→  if (detachedWindow && !detachedWindow.isDestroyed()) {
507→    detachedWindow.close();
508→    detachedWindow = null;
509→  }
510→}
